					//5		101
					bits2 = bits1 += bits0 = GET_BITS(5);
					HANDLE_BITS1(0, bits0);
					HANDLE_BITS0(1, bits1);
					//6		110
					bits1 = bits0 = GET_BITS(6);
					HANDLE_BITS0(0, bits0);
					//7		111
					bits3 += bits2 += bits1 += bits0 = GET_BITS(7);
