					//1
					bits2 = bits1 += bits0 = GET_BITS(1);
					HANDLE_BITS(0,bits0);
					HANDLE_BITS(1,bits1);
					//2
					bits1 = bits0 = GET_BITS(2);
					HANDLE_BITS(0,bits0);
					//3
					bits3 = bits2 += bits1 += bits0 = GET_BITS(3);
					HANDLE_BITS(0,bits0);
					HANDLE_BITS(1,bits1);
					HANDLE_BITS(2,bits2);
					//4
					bits1 = bits0 = GET_BITS(4);
					HANDLE_BITS(0,bits0);
					//5
					bits2 = bits1 += bits0 = GET_BITS(5);
					HANDLE_BITS(0,bits0);
